// ===== AGENT TCG POCKET — scrape + mémoire + édito variable =====
const h = $('Limitless Pocket').first().json.data;
let prev=null; try{ prev=$('Veille tcgp').first().json; }catch(e){}
const strip=s=>String(s||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
const now=new Date(), iso=now.toISOString();
const jours=['dimanche','lundi','mardi','mercredi','jeudi','vendredi','samedi'];
const seed=now.getDate()+now.getMonth()*31;
const rows=[...String(h).matchAll(/<tr[\s\S]*?<\/tr>/g)].map(m=>m[0]);
const pocket=[];
for(const r of rows){
  const a=r.match(/<a[^>]*href="\/decks\/([^"?]+)[^"]*"[^>]*>([\s\S]*?)<\/a>/); if(!a) continue;
  const t=strip(r);
  const n=t.match(/(\d[\d\s]*)\s+([\d.]+)%\s+(\d+)\s*-\s*(\d+)\s*-\s*(\d+)\s+([\d.]+)%/); if(!n) continue;
  pocket.push({name:strip(a[2]),slug:a[1],count:parseInt(n[1].replace(/\s/g,'')),share:parseFloat(n[2]),record:n[3]+'-'+n[4]+'-'+n[5],wr:parseFloat(n[6])});
}
if(pocket.length<5) throw new Error('Parseur Pocket KO ('+pocket.length+') — structure Limitless changée ?');
const prevTop=(prev&&prev.topUsage)||[];
const pr={}; prevTop.forEach((d,i)=>pr[d.name]=i+1);
const topU=pocket.slice(0,10).map((d,i)=>Object.assign({rank:i+1,move:pr[d.name]==null?'new':(pr[d.name]>i+1?'up':(pr[d.name]<i+1?'down':'stable'))},d));
const eligible=pocket.filter(d=>d.share>=2);
const topW=eligible.slice().sort((a,b)=>b.wr-a.wr).slice(0,10);
const fresh=new Set(topU.map(d=>d.name));
const entering=prevTop.length?topU.filter(d=>!pr[d.name]).map(d=>d.name+' ('+d.wr+'% WR)'):[];
const leaving=prevTop.map(d=>d.name).filter(n=>!fresh.has(n));
const movers=topU.filter(d=>d.move==='up'||d.move==='new'), droppers=topU.filter(d=>d.move==='down');
const spot=topU[seed%topU.length], best=topW[0];
const sleeper=pocket.filter(d=>d.share<2&&d.share>0.3).sort((a,b)=>b.wr-a.wr)[0];
const angles=[
 ()=>"Zoom du "+jours[now.getDay()]+" : "+spot.name+" — "+spot.share+"% d'usage pour "+spot.wr+"% de winrate ("+spot.record+"). "+(spot.wr>=51?"Un choix solide en ce moment.":"Populaire mais contestable : la méta a ses réponses."),
 ()=>"Le deck à battre reste "+best.name+" ("+best.wr+"% WR sur "+best.count+" listes)."+(sleeper?" En embuscade : "+sleeper.name+" à "+sleeper.wr+"% WR sur petit volume.":""),
 ()=>eligible.length+" archétypes au-dessus de 2% d'usage. L'écart entre le plus joué ("+topU[0].name+", "+topU[0].share+"%) et le plus performant ("+best.name+", "+best.wr+"%) "+(topU[0].name===best.name?"a disparu.":"reste le vrai sujet du format."),
 ()=>"Stabilité du top 10 : "+(10-movers.length-droppers.length)+"/10 inchangés. "+(movers.length?"En progression : "+movers.slice(0,2).map(d=>d.name).join(', ')+".":"Le format attend son prochain catalyseur (B3b ?).")
];
const summary=(movers.length>=2||entering.length)
 ? "Mouvement dans la méta : "+(entering[0]||movers[0].name+" grimpe")+(droppers.length?" tandis que "+droppers[0].name+" recule":"")+". Meilleur WR jouable : "+best.name+" ("+best.wr+"%). Le plus joué : "+topU[0].name+" ("+topU[0].share+"%)."
 : angles[seed%angles.length]();
const keep=(list,n,f)=>{const o=(list||[]).find(x=>x.name===n);return o?o[f]:undefined;};
const out=Object.assign({},prev||{},{
 metaSummary:summary,
 topUsage:topU.map(d=>({rank:d.rank,name:d.name,usage:d.share,winrate:d.wr,record:d.record,winRate:d.wr,share:d.share,move:d.move,limitless:d.slug,cards:keep(prevTop,d.name,'cards'),listBy:keep(prevTop,d.name,'listBy')})),
 topWinrate:topW.map((d,i)=>({rank:i+1,name:d.name,winrate:d.wr,usage:d.share,record:d.record,winRate:d.wr,share:d.share,limitless:d.slug,cards:keep(prev&&prev.topWinrate,d.name,'cards'),listBy:keep(prev&&prev.topWinrate,d.name,'listBy')})),
 enteringMeta:entering.length?entering:(sleeper?[sleeper.name+' ('+sleeper.wr+'% WR, outsider)']:[]),
 leavingMeta:leaving,
 movements:topU.map(d=>({slug:d.slug,name:d.name,rank:d.rank,usage:d.share,move:d.move})),
 totalDecks:pocket.length, updatedAt:iso });
out.topDecks=out.topUsage;
return [{json:{content:JSON.stringify(out,null,2),msg:"bot(pocket) "+now.toLocaleDateString('fr-FR')+" : "+(movers.length+droppers.length)+" mouvements"+(entering.length?", entrée "+entering[0]:"")}}];
